```cpp
__shared__ float smem[rows_per_tile][kBlockSize / kWavefront]; // [rows_per_tile][4]
// kBlockSize=256, kWavefront=64, so 4 warps

for(int r = 0; r < rows_per_tile; r++)
{
    float partial = partial_sums[r];
    // Warp-level reduction
    for(int i = 1; i < kWavefront; i <<= 1)
        partial += __shfl_down(partial, i);
    // Warp 0 of each wavefront writes to shared memory
    int warp_id = thread / kWavefront;
    int lane = thread % kWavefront;
    if(lane == 0)
        smem[r][warp_id] = partial;
    __syncthreads();
    // Warp 0 reduces the 4 values
    if(warp_id == 0 && lane < (kBlockSize / kWavefront))
    {
        float val = smem[r][lane];
        for(int i = 1; i < (kBlockSize / kWavefront); i <<= 1)
            val += __shfl_down(val, i);
        if(lane == 0)
            smem[r][0] = val;
    }
