            weight_offset += kAtomStride * sizeof(int32x4_t);
        }
    }

    // Add residual, store residual_out, compute partial sum of squares
    float row_sq[kAtoms] = {};
    {
        BufferResource res_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
        BufferResource res_out_buffer(residual_out, N * sizeof(T));
        uint32_t res_offset = block * kTileSize + thread * sizeof(int32x4_t);
        uint32_t res_out_offset = res_offset;

        for(int i = 0; i < kAtoms; i++)
        {
            int32x4_t res_atom = buffer_load_dwordx4(res_buffer.descriptor, res_offset, 0, 0);
            res_offset += kAtomStride * sizeof(int32x4_t);

            // sum = tA[i] + res_atom (in T)
            int32x4_t sum_atom;
    #pragma unroll
            for(int j = 0; j < 4; j++)
            {
                sum_atom[j] = packed_add<T>(tA[i][j], res_atom[j]);
            }

            // Store residual_out
            buffer_store_dwordx4(sum_atom, res_out_buffer.descriptor, res_out_offset, 0, 0);
            res_out_offset += kAtomStride * sizeof(int32x4_t);

            // Accumulate sum of squares for this row
            int row = i / (int)atoms_per_row;
            T const* sum_elem = reinterpret_cast<T const*>(&sum_atom);
    #pragma unroll
            for(int e = 0; e < kElemsPerAtom; e++)
            {
                float val = qr_to_float<T>(sum_elem[e]);
                row_sq[row] += val * val;
            }

            // Save sum back to tA for output computation
            tA[i] = sum_atom;
        }
    }

    // Reduce partial sums across the block (warp shuffle + shared memory)
    constexpr int kNumWarps = kBlockSize / kWavefront;
    __shared__ float smem[kAtoms * kNumWarps];

    int warp_id = thread / kWavefront;
    int lane = thread % kWavefront;

    for(uint32_t r = 0; r < rows_per_tile; r++)
    {
        float val = row_sq[r];
        for(int s = 1; s < kWavefront; s <<= 1)
            val += __shfl_down(val, s);
        if(lane == 0)
            smem[r * kNumWarps + warp_id] = val;
    }
    __syncthreads();

    if(warp_id == 0)
    {
        for(uint32_t r = 0; r < rows_per_tile; r++)
        {
            float v = (lane < kNumWarps) ? smem[r * kNumWarps + lane] : 0.0f;
            for(int s = 1; s < kNumWarps; s <<= 1)
                v += __shfl_down(v, s);
            if(lane == 0)
                smem[r * kNumWarps] = v;
        }
    }
    __syncthreads();

    // Compute denoms
    float denoms[kAtoms] = {};
    for(uint32_t r = 0; r < rows_per_tile; r++)
    {
        denoms[r] = rsqrtf(smem[r * kNumWarps] / (float)hidden_dim + eps);
    }

    // Compute output = sum * denom * weight, store to output
    {
        BufferResource out_buffer(output, N * sizeof(T));
        uint32_t out_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            int row = i / (int)atoms_per_row;
            int a = i % (int)atoms_per_row;
            float denom = denoms[row];

            T const* sum_elem = reinterpret_cast<T const*>(&tA[i]);
            T const* weight_elem = reinterpret_cast<T const*>(&w_atoms[a]);
            int32x4_t out_atom;
            T* out_elem = reinterpret_cast<T*>(&out_atom);
    #pragma unroll
            for(int e = 0; e < kElemsPerAtom; e++)
            {
                float val = qr_to_float<T>(sum_elem[e]);
                float w = qr_to_float<T>(weight_elem[e]);
                out_elem[e] = qr_from_float<T>(val * denom * w);
            }
            buffer_store_dwordx4(out_atom, out_buffer.descriptor, out_offset, 0, 0);
            out_offset += kAtomStride * sizeof(int32x4_t);
        }
    }
}
