```cpp
__device__ static void run(T const* __restrict__ input,
                           T const* __restrict__ residual_inp,
                           T* __restrict__ residual_out,
                           T* __restrict__ output,
                           T const* __restrict__ weight,
                           float eps,
                           uint32_t const N,
                           uint32_t const hidden_dim,
                           int const block,
                           int const rank,
                           uint8_t** __restrict__ buffer_list,
                           uint32_t const data_offset,
                           uint32_t flag_color,
                           int64_t data_size_per_phase)
{
    // ============================================================
    // Part 1: Two-shot quick all-reduce (mirrors AllReduceTwoshot::run)
    // ============================================================
    int thread           = threadIdx.x + threadIdx.y * kWavefront;
    uint8_t* rank_buffer = buffer_list[rank];
    Codec codec(thread, rank);
    int block_id         = blockIdx.x;
    uint8_t* buffer_ptr[kWorldSize];
    for(int i = 0; i < kWorldSize; ++i)
    {
        buffer_ptr[i] = buffer_list[i];
    }

    // Read input into registers
    int32x4_t tA[kAtoms];
    BufferResource src_buffer(const_cast<T*>(input), N * sizeof(T));
    uint32_t src_offset = block * kTileSize + thread * sizeof(int32x4_t);
    for(int i = 0; i < kAtoms; i++)
    {
        tA[i] = buffer_load_dwordx4(src_buffer.descriptor, src_offset, 0, 0);
        src_offset += kAtomStride * sizeof(int32x4_t);
        if constexpr(cast_bf2half)
        {
            const nv_bfloat162* bf_buf = reinterpret_cast<const nv_bfloat162*>(&tA[i]);
            half2 half_buf[4];
#pragma unroll
            for(int j = 0; j < 4; ++j)
            {
                float2 f    = __bfloat1622float2(bf_buf[j]);
                half_buf[j] = __float22half2_rn(f);
            }
            tA[i] = *reinterpret_cast<const int32x4_t*>(half_buf);
        }
    }

    // Phase-1A: Write segment data into the communication buffer of the target rank
    uint32_t comm_data0_offset = data_offset + block_id * Codec::kTransmittedTileSize;
    uint32_t comm_data1_offset = data_size_per_phase + comm_data0_offset;
    uint32_t comm_flags0_offset = block_id * (kWorldSize * sizeof(uint32_t));
    uint32_t comm_flags1_offset = (data_offset / 2) + comm_flags0_offset;

    for(int r = 0; r < kWorldSize; r++)
    {
        int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
            buffer_ptr[r] + comm_data0_offset + rank * Codec::kRankTransmittedTileSize);
        codec.send(send_buffer, &tA[r * Codec::kRankAtoms]);
    }

    __syncthreads();
    if(thread < kWorldSize)
    {
        int r               = thread;
        uint32_t* flag_ptr  = reinterpret_cast<uint32_t*>(
            buffer_ptr[r] + comm_flags0_offset + rank * sizeof(uint32_t));
        set_sync_flag(flag_ptr, flag_color);
    }

    // Phase-1B: Reduce the segment data from the communication buffers
    int32x4_t tR[Codec::kRankAtoms] = {};
    {
        int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data0_offset);
        uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags0_offset);
        for(int r = 0; r < kWorldSize; r++)
        {
            if(thread == 0)
            {
                wait_sync_flag(&flag_ptr[r], flag_color);
            }
            __syncthreads();
            codec.recv(&recv_buffer, tA);
            for(int i = 0; i < Codec::kRankAtoms; i++)
            {
                packed_assign_add<CommT>(&tR[i], &tA[i]);
            }
        }
    }

    // Phase-2: Write the reduced segment to every other rank
    for(int r = 0; r < kWorldSize; r++)
    {
        int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
            buffer_ptr[r] + comm_data1_offset + rank * Codec::kRankTransmittedTileSize);
        codec.send(send_buffer, tR);
    }

    __syncthreads();
    if(thread < kWorldSize)
    {
        int r               = thread;
        uint32_t* flag_ptr  = reinterpret_cast<uint32_t*>(
            buffer_ptr[r] + comm_flags1_offset + rank * sizeof(uint32_t));
        set_sync_flag(flag_ptr, flag_color);
    }

    // Phase-2: Read the gather segments from the rank's communication buffer
    {
        int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data1_offset);
        uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags1_offset);
        for(int r = 0; r < kWorldSize; r++)
        {
            if(thread == 0)
            {
                wait_sync_flag(&flag_ptr[r], flag_color);
            }
            __syncthreads();
            codec.recv(&recv_buffer, &tA[r * Codec::kRankAtoms]);
        }
    }

    // ============================================================
    // Part 2: Convert CommT -> T (if cast_bf2half)
    // ============================================================
    if constexpr(cast_bf2half)
    {
        for(int i = 0; i < kAtoms; i++)
        {
            const half2* half_buf = reinterpret_cast<const half2*>(&tA[i]);
            nv_bfloat162 bf16_buf[4];
#pragma unroll
            for(int j = 0; j < 4; ++j)
            {
                float2 f      = __half22float2(half_buf[j]);
                bf16_buf[j]   = __float22bfloat162_rn(f);
            }
            tA[i] = *reinterpret_cast<const int32x4_t*>(bf16_buf);
        }
    }

    // ============================================================
    // Part 3: Add residual + RMSNorm epilogue
    // ============================================================
    uint32_t row_size_bytes = hidden_dim * (uint32_t)sizeof(T);
    uint32_t rows_per_tile  = kTileSize / row_size_bytes;
    uint32_t atoms_per_row  = (uint32_t)kAtoms / rows_per_tile;

    // Load weight (once, reused across all rows in this tile)
    int32x4_t w_atoms[kAtoms];
    {
        BufferResource weight_buffer(const_cast<T*>(weight), hidden_dim * sizeof(T));
        uint32_t weight_offset = thread * sizeof(int32x4_t);
        for(uint32_t a = 0; a < atoms_per_row; a++)
        {
            w_atoms[a] = buffer_load_dwordx4(weight_buffer.descriptor, weight_offset, 0, 0);
            weight_offset += kAtomStride * sizeof(int32x4_t);
        }
    }

    // Add residual, store residual_out, compute partial sum of squares
    float row_sq[kAtoms] = {};
    {
        BufferResource res_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
        BufferResource res_out_buffer(residual_out, N * sizeof(T));
        uint32_t res_offset     = block * kTileSize + thread * sizeof(int32x4_t);
        uint32_t res_out_offset = res_offset;

        for(int i = 0; i < kAtoms; i++)
        {
            int32x4_t res_atom = buffer_load_dwordx4(res_buffer.descriptor, res_offset, 0, 0);
            res_offset += kAtomStride * sizeof(int32x4_t);

            // sum = reduced_value + residual (in T)
            int32x4_t sum_atom;
#pragma unroll
            for(int j = 0; j < 4; j++)
            {
                sum_atom[j] = packed_add<T>(tA[i][j], res_atom[j]);
            }

            // Store residual_out
            buffer_store_dwordx4(sum_atom, res_out_buffer.descriptor, res_out_offset, 0, 0);
            res_out_offset += kAtomStride * sizeof(int32x4_t);

            // Accumulate sum of squares for this row (in float for accuracy)
            int row = i / (int)atoms_per_row;
            T const* sum_elem = reinterpret_cast<T const*>(&sum_atom);
#pragma unroll
            for(int e = 0; e < kElemsPerAtom; e++)
            {
                float val = qr_to_float<T>(sum_elem[e]);
                row_sq[row] += val * val;
            }

            // Save sum back to tA for output computation
            tA[i] = sum_atom;
        }
    }

    // Block-level reduction of partial sums of squares (warp shuffle + smem)
    constexpr int kNumWarps = kBlockSize / kWavefront;
    __shared__ float smem[kAtoms * kNumWarps];

    int warp_id = thread / kWavefront;
    int lane    = thread % kWavefront;

    // Warp-level reduction
    for(uint32_t r = 0; r < rows_per_tile; r++)
    {
        float val = row_sq[r];
        for(int s = 1; s < kWavefront; s <<= 1)
            val += __shfl_down(val, s);
        if(lane == 0)
            smem[r * kNumWarps + warp_id] = val;
    }
    __syncthreads();

    // Final reduction across warps (warp 0 only)
    if(warp_id == 0)
    {
        for(uint32_t r = 0; r < rows_per_tile; r++)
        {
            float v = (lane < kNumWarps) ? smem[r * kNumWarps + lane] : 0.0f;
            for(int s = 1; s < kNumWarps; s <<= 1)
                v += __shfl_down(v, s);
            if(lane == 0)
                smem[r * kNumWarps] = v;
        }
    }
    __syncthreads();

    // Compute RMSNorm denominators
    float denoms[kAtoms] = {};
    for(uint32_t r = 0; r < rows_per_tile; r++)
    {
        denoms[r] = rsqrtf(smem[r * kNumWarps] / (float)hidden_dim + eps);
    }

    // Compute output = sum * denom * weight, store to output
    {
        BufferResource out_buffer(output, N * sizeof(T));
        uint32_t out_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            int row   = i / (int)atoms_per_row;
            int a     = i % (int)atoms_per_row;
            float denom = denoms[row];

            T const* sum_elem    = reinterpret_cast<T const*>(&tA[i]);
            T const* weight_elem = reinterpret_cast<T const*>(&w_atoms[a]);
            int32x4_t out_atom;
            T* out_elem = reinterpret_cast<T*>(&out_atom);
#pragma unroll
            for(int e = 0; e < kElemsPerAtom; e++)
            {
                float val = qr_to_float<T>(sum_elem[e]);
                float w   = qr_to_float<T>(weight_elem[e]);
                out_elem[e] = qr_from_float<T>(val * denom * w);
            }
            buffer_store_dwordx4(out_atom, out_buffer.descriptor, out_offset, 0, 0);
            out_offset += kAtomStride * sizeof(int32x4_t);
        }
    }
}
